select key, empresa_id, ativo, value from public.app_config where key in ('finance.wallet_account_enabled','finance.wallet_ledger_enabled','finance.cockpit_v2_enabled','finance.cockpit_v2_compare_enabled','finance.financial_alerts_v2_enabled','finance.reports_v2_enabled','finance.legacy_cockpit_finance_disabled','finance.payment_v2_write_enabled','finance.payment_v2_reversal_enabled') order by key, empresa_id nulls first;
